import{_ as o,c as t,o as i,ag as s}from"./chunks/framework.GdcW6lnn.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/wire-mock.md","filePath":"basics_api/wire-mock.md"}'),l={name:"basics_api/wire-mock.md"};function n(e,r,g,a,c,p){return i(),t("div",null,r[0]||(r[0]=[s('<h3 id="🧱-wiremock-створення-імітаціи-моків-api-для-ізольованого-тестування" tabindex="-1">🧱 WireMock: Створення імітацій (моків) API для ізольованого тестування <a class="header-anchor" href="#🧱-wiremock-створення-імітаціи-моків-api-для-ізольованого-тестування" aria-label="Permalink to “🧱 WireMock: Створення імітацій (моків) API для ізольованого тестування”">​</a></h3><p><strong>Що це?</strong></p><p>WireMock - це <strong>інструмент для створення &quot;мок-сервісів&quot; (mock services)</strong>. Він дозволяє вам <strong>імітувати поведінку реальних API</strong>, визначаючи, які запити він повинен приймати та які відповіді повертати для цих запитів. Це особливо корисно для <strong>ізольованого тестування</strong> вашого коду, який залежить від зовнішніх API, коли ці API ще не розроблені, нестабільні, дорогі у використанні під час тестування або їхнє тестування є складним.</p><p><strong>Основні можливості та їх детальний огляд:</strong></p><ul><li><p><strong>🎭 Створення стабів (Stubs):</strong></p><ul><li>Визначення <strong>очікуваних запитів:</strong> Ви можете точно налаштувати, на які HTTP-метод (GET, POST, PUT, DELETE тощо), URL, заголовки та тіло запиту WireMock повинен реагувати.</li><li>Визначення <strong>відповідних відповідей:</strong> Для кожного очікуваного запиту ви можете задати, який HTTP-статус-код, заголовки та тіло відповіді (у будь-якому форматі, наприклад, JSON, XML, текст) повинен повернути WireMock.</li><li><strong>Гнучкі критерії зіставлення:</strong> WireMock надає різні способи зіставлення вхідних запитів з визначеними стабами (наприклад, точна відповідність URL, відповідність за регулярним виразом, перевірка наявності заголовків, відповідність частини тіла запиту).</li></ul></li><li><p><strong>🚦 Імітація різних сценаріїв:</strong></p><ul><li><strong>Успішні відповіді:</strong> Моделювання очікуваної поведінки API при успішному виконанні запиту.</li><li><strong>Помилки:</strong> Імітація різних типів помилок сервера (наприклад, 400 Bad Request, 500 Internal Server Error) для перевірки обробки помилок у вашому коді.</li><li><strong>Затримки:</strong> Симуляція затримок у відповіді API для тестування тайм-аутів та обробки повільних мережевих з&#39;єднань у вашому коді.</li><li><strong>Перенаправлення:</strong> Імітація HTTP-перенаправлень (301, 302 тощо).</li></ul></li><li><p><strong>✅ Перевірка запитів:</strong></p><ul><li>WireMock може записувати всі запити, які надходять до нього.</li><li>Ви можете використовувати API WireMock для <strong>перевірки того, що ваш код надсилав очікувані запити</strong> до імітованого API (наприклад, перевірити, який метод використовувався, на який URL надсилався запит, які заголовки та тіло він містив, скільки разів він був викликаний).</li></ul></li><li><p><strong>🧱 Ізольоване тестування:</strong></p><ul><li>Використовуючи WireMock, ви можете <strong>повністю ізолювати свій код від залежностей від зовнішніх API</strong> під час тестування. Це робить тести більш швидкими, надійними та передбачуваними, оскільки вони не залежать від стану зовнішніх сервісів.</li><li>Це особливо корисно для юніт-тестів та інтеграційних тестів.</li></ul></li><li><p><strong>🏃 Запуск як окремий процес або вбудована бібліотека:</strong></p><ul><li>WireMock може бути запущений як <strong>окремий HTTP-сервер</strong> (standalone), до якого ваш код надсилатиме запити замість реального API.</li><li>Він також може бути <strong>вбудований безпосередньо у ваші тести</strong> як бібліотека (наприклад, JUnit rule або TestNG listener у Java), що спрощує налаштування та керування мок-сервісом під час виконання тестів.</li></ul></li><li><p><strong>📝 Конфігурація через код або JSON:</strong></p><ul><li>Стаби можуть бути визначені <strong>програмно</strong> за допомогою API WireMock (наприклад, на Java).</li><li>Їх також можна визначати <strong>декларативно</strong> у вигляді JSON-файлів, які WireMock завантажує під час запуску.</li></ul></li><li><p><strong>🔄 Зміна поведінки моків під час виконання тестів:</strong></p><ul><li>API WireMock дозволяє динамічно змінювати поведінку імітованих API під час виконання тестів, що дає змогу тестувати різні сценарії.</li></ul></li></ul><p><strong>Приклади використання:</strong></p><ul><li><strong>Юніт-тестування сервісів, що споживають API:</strong> Замість того, щоб робити реальні HTTP-виклики до зовнішнього API, ви налаштовуєте WireMock на повернення заздалегідь визначених відповідей та перевіряєте, чи ваш сервіс правильно обробляє ці відповіді.</li><li><strong>Інтеграційне тестування:</strong> Тестування взаємодії між різними компонентами вашої системи, де один компонент залежить від API іншого. Ви можете використовувати WireMock для імітації поведінки залежного API.</li><li><strong>Розробка фронтенду без готового бекенду:</strong> Фронтенд-розробники можуть використовувати WireMock для створення мок-сервісів, які повертають очікувані дані, що дозволяє їм розробляти інтерфейс до того, як буде готовий реальний бекенд.</li><li><strong>Тестування обробки помилок та крайніх випадків:</strong> Легко імітувати різні сценарії помилок та перевіряти, чи ваш код їх правильно обробляє (наприклад, повторні спроби, повідомлення про помилки).</li></ul><p><strong>Візуалізація:</strong> Уявіть WireMock як <strong>конструктор LEGO для API</strong> 🧱. Ви можете створювати власні &quot;фейкові&quot; API з точно визначеною поведінкою для конкретних тестів. Це дозволяє вам контролювати зовнішні залежності та зосередитися на тестуванні логіки вашого власного коду в ізольованому середовищі, роблячи ваші тести більш надійними та передбачуваними.</p>',8)]))}const k=o(l,[["render",n]]);export{u as __pageData,k as default};
